func UpdatedAtLT(v time.Time) predicate.AgentSessionSummary {
	return predicate.AgentSessionSummary(sql.FieldLT(FieldUpdatedAt, v))
}

// UpdatedAtLTE applies the LTE predicate on the "updated_at" field.
func UpdatedAtLTE(v time.Time) predicate.AgentSessionSummary {
	return predicate.AgentSessionSummary(sql.FieldLTE(FieldUpdatedAt, v))
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentSessionSummary) predicate.AgentSessionSummary {
	return predicate.AgentSessionSummary(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentSessionSummary) predicate.AgentSessionSummary {
	return predicate.AgentSessionSummary(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentSessionSummary) predicate.AgentSessionSummary {
	return predicate.AgentSessionSummary(sql.NotPredicates(p))
}
